solution.javascript:
import { test, expect } from '@playwright/test';

test('use different locators', async ({ page }) => {
  await page.goto('https://demo.playwright.dev/todomvc');

  const inputByCSS = page.locator('.new-todo');
  await expect(inputByCSS).toBeVisible();

  const inputByPlaceholder = page.getByPlaceholder('What needs to be done?');
  await inputByPlaceholder.fill('First Todo');
  await inputByPlaceholder.press('Enter');

  const todoByText = page.getByText('First Todo');
  await expect(todoByText).toBeVisible();

  await inputByPlaceholder.fill('Second Todo');
  await inputByPlaceholder.press('Enter');

  const todoList = page.locator('.todo-list');
  const firstTodo = todoList.locator('li').first();
  await expect(firstTodo).toContainText('First Todo');

  const filteredTodo = page.locator('.todo-list li').filter({ hasText: 'Second' });
  await expect(filteredTodo).toBeVisible();
});

